export type SerialFlashOutcome = { result: "verified"; board_id: number; bootloader_rev: number; port: string } | { result: "cancelled" } | { result: "flashed_but_unverified"; board_id: number; bootloader_rev: number; port: string } | { result: "reconnect_verified"; board_id: number; bootloader_rev: number; flash_verified: boolean } | { result: "reconnect_failed"; board_id: number; bootloader_rev: number; flash_verified: boolean; reconnect_error: string } | { result: "failed"; reason: string } | { result: "board_detection_failed"; reason: string } | { result: "extf_capacity_insufficient"; reason: string };

export type SerialFlashPhase = "idle" | "probing" | "erasing" | "programming" | "verifying" | "rebooting";

export type SerialFlashSource = { kind: "catalog_url"; url: string } | { kind: "local_apj_bytes"; data: number[] };

/**
 *  Terminal result of a serial flash flow execution.
 *  Distinguishes verified from unverified outcomes explicitly.
 */
export type SerialFlowResult =
/**  Flash succeeded and CRC verification passed. */
{ result: "verified"; board_id: number; bootloader_rev: number; port: string } |
/**  Flash completed but CRC verification was unavailable (BL_REV < 3). */
{ result: "flashed_but_unverified"; board_id: number; bootloader_rev: number; port: string } |
/**  Flash completed and verified/unverified, plus reconnect succeeded. */
{ result: "reconnect_verified"; board_id: number; bootloader_rev: number; flash_verified: boolean } |
/**  Flash completed but reconnect verification failed or timed out. */
{ result: "reconnect_failed"; board_id: number; bootloader_rev: number; flash_verified: boolean; reconnect_error: string } |
/**  Flash was cancelled before completion. */
{ result: "cancelled" } |
/**  Serial flow failed and may need manual recovery. Never auto-enters DFU. */
{ result: "failed"; reason: string } |
/**  Board detection during bootloader phase failed. */
{ result: "board_detection_failed"; reason: string } |
/**  Board lacks sufficient external-flash capacity for the firmware artifact. */
{ result: "extf_capacity_insufficient"; reason: string };

